	w.Header().Set("Content-Type", contentType)
	w.Header().Set("Content-Length", strconv.FormatInt(info.Size(), 10))
	w.Header().Set("Content-Disposition", `inline; filename="`+info.Name()+`"`)

	http.ServeContent(w, r, info.Name(), info.ModTime(), f)
